.darma-loader-darma-custom-394 {
  width: 50px;
  aspect-ratio: 1;
  color: var(--loader-color, #16a34a);
  background:radial-gradient(circle at 60% 65%, currentColor 62%, #0000 65%) top left,radial-gradient(circle at 40% 65%, currentColor 62%, #0000 65%) top right,linear-gradient(to bottom left, currentColor 42%,#0000 43%) bottom left ,linear-gradient(to bottom right,currentColor 42%,#0000 43%) bottom right;
  background-size: 50% 50%;
  background-repeat: no-repeat;
  position: relative;
}.darma-loader-darma-custom-394:before {content: "";
  position: absolute;
  inset: 0;
  background: inherit;
  opacity: 0.4;
  animation: darma-loader-darma-custom-394-l3 1s infinite;
}@keyframes darma-loader-darma-custom-394-l3 {to {transform: scale(1.8);
  opacity:0}}

